import React from 'react';
import { useNavigate } from 'react-router-dom';
import './WelcomeScreen.css';

const WelcomeScreen = ({ language, onLanguageChange, state, onStateChange }) => {
  const navigate = useNavigate();
  const languages = [
    { code: 'en', name: 'English', flag: '🇬🇧' },
    { code: 'hi', name: 'हिंदी', flag: '🇮🇳' },
    { code: 'ta', name: 'தமிழ்', flag: '🇮🇳' },
    { code: 'te', name: 'తెలుగు', flag: '🇮🇳' },
    { code: 'bn', name: 'বাংলা', flag: '🇮🇳' },
    { code: 'kn', name: 'ಕನ್ನಡ', flag: '🇮🇳' },
    { code: 'mr', name: 'मराठी', flag: '🇮🇳' }
  ];

  const states = [
    { code: 'MH', name: { en: 'Maharashtra', hi: 'महाराष्ट्र' }, laws: 'POSH 2013 + UGC 2009 + Maharashtra Ragging Act' },
    { code: 'DL', name: { en: 'Delhi', hi: 'दिल्ली' }, laws: 'POSH 2013 + UGC 2009 + Delhi Ragging Act' },
    { code: 'TN', name: { en: 'Tamil Nadu', hi: 'तमिलनाडु' }, laws: 'POSH 2013 + UGC 2009 + TN Ragging Act 1997' },
    { code: 'KA', name: { en: 'Karnataka', hi: 'कर्नाटक' }, laws: 'POSH 2013 + UGC 2009 + Karnataka Ragging Act' },
    { code: 'WB', name: { en: 'West Bengal', hi: 'पश्चिम बंगाल' }, laws: 'POSH 2013 + UGC 2009 + WB Ragging Act' }
  ];

  const content = {
    en: {
      title: 'Welcome to Sahayak AI',
      subtitle: 'A safe space for students facing crisis situations',
      selectState: 'Select Your State',
      legalFramework: 'Legal Framework',
      features: [
        '🔒 Anonymous & Confidential',
        '🌐 English & Hindi Support',
        '🤝 Empathetic AI Assistance',
        '📞 Direct Resource Connections',
        '⚡ Immediate Safety Guidance',
        '🛡️ Available 24/7'
      ],
      crisisTypes: 'We can help with:',
      types: [
        'Harassment & POSH Issues',
        'Ragging Incidents',
        'Cyberbullying',
        'Mental Health Support',
        'Self-harm Crisis',
        'Physical Safety Threats'
      ],
      privacy: 'Your Privacy Matters',
      privacyText: 'We do not collect personal information unless you choose to share it. All conversations are encrypted and automatically deleted after 7 days.',
      startButton: 'Start Conversation',
      emergency: 'If you are in immediate danger, please call 112'
    },
    hi: {
      title: 'सहायक AI में आपका स्वागत है',
      subtitle: 'संकट की स्थिति का सामना कर रहे छात्रों के लिए एक सुरक्षित स्थान',
      selectState: 'अपना राज्य चुनें',
      legalFramework: 'कानूनी ढांचा',
      features: [
        '🔒 गुमनाम और गोपनीय',
        '🌐 अंग्रेजी और हिंदी समर्थन',
        '🤝 सहानुभूतिपूर्ण AI सहायता',
        '📞 प्रत्यक्ष संसाधन कनेक्शन',
        '⚡ तत्काल सुरक्षा मार्गदर्शन',
        '🛡️ 24/7 उपलब्ध'
      ],
      crisisTypes: 'हम इसमें मदद कर सकते हैं:',
      types: [
        'उत्पीड़न और POSH मुद्दे',
        'रैगिंग की घटनाएं',
        'साइबरबुलिंग',
        'मानसिक स्वास्थ्य सहायता',
        'आत्म-हानि संकट',
        'शारीरिक सुरक्षा खतरे'
      ],
      privacy: 'आपकी गोपनीयता मायने रखती है',
      privacyText: 'हम व्यक्तिगत जानकारी एकत्र नहीं करते जब तक आप इसे साझा करना नहीं चुनते। सभी बातचीत एन्क्रिप्टेड हैं और 7 दिनों के बाद स्वचालित रूप से हटा दी जाती हैं।',
      startButton: 'बातचीत शुरू करें',
      emergency: 'यदि आप तत्काल खतरे में हैं, तो कृपया 112 पर कॉल करें'
    }
  };

  const text = content[language];

  return (
    <div className="welcome-screen">
      <div className="welcome-card">
        <div className="welcome-header">
          <h2>{text.title}</h2>
          <p className="subtitle">{text.subtitle}</p>
        </div>

        <div className="welcome-content">
          <div className="state-selector-section">
            <h3>📍 {text.selectState}</h3>
            <div className="state-selector">
              {states.map((s) => (
                <button
                  key={s.code}
                  className={`state-btn ${state === s.code ? 'active' : ''}`}
                  onClick={() => onStateChange(s.code)}
                >
                  {s.name[language]}
                </button>
              ))}
            </div>
            {state && (
              <div className="legal-framework-display">
                <strong>{text.legalFramework}:</strong> {states.find(s => s.code === state)?.laws}
              </div>
            )}
          </div>

          <div className="features-section">
            <div className="features-grid">
              {text.features.map((feature, index) => (
                <div key={index} className="feature-item">
                  {feature}
                </div>
              ))}
            </div>
          </div>

          <div className="crisis-types-section">
            <h3>{text.crisisTypes}</h3>
            <div className="crisis-types-grid">
              {text.types.map((type, index) => (
                <div key={index} className="crisis-type-item">
                  ✓ {type}
                </div>
              ))}
            </div>
          </div>

          <div className="privacy-section">
            <h3>🔐 {text.privacy}</h3>
            <p>{text.privacyText}</p>
          </div>

          <button className="start-button" onClick={onStart}>
            {text.startButton}
          </button>

          <div className="language-selector">
            <button 
              className={`lang-btn ${language === 'en' ? 'active' : ''}`}
              onClick={() => onLanguageChange('en')}
            >
              <span className="flag">🇬🇧</span>
              English
            </button>
            <button 
              className={`lang-btn ${language === 'hi' ? 'active' : ''}`}
              onClick={() => onLanguageChange('hi')}
            >
              <span className="flag">🇮🇳</span>
              हिंदी
            </button>
          </div>

          <div className="emergency-notice">
            ⚠️ {text.emergency}
          </div>
        </div>
      </div>
    </div>
  );
};

export default WelcomeScreen;
